export const BOARD_SIZE = 4
export type Direction = 'up' | 'down' | 'left' | 'right'
export type Status = 'playing' | 'won' | 'game-over'

export interface MoveResult {
  board: number[][]
  scoreGained: number
  moved: boolean
  won: boolean
}

export interface GameState {
  board: number[][]
  score: number
  status: Status
}

export function createEmptyBoard(): number[][] {
  return Array.from({ length: BOARD_SIZE }, () => Array(BOARD_SIZE).fill(0))
}

function cloneBoard(board: number[][]): number[][] {
  return board.map((row) => [...row])
}

function getEmptyCells(board: number[][]): Array<[number, number]> {
  const empty: Array<[number, number]> = []
  for (let r = 0; r < BOARD_SIZE; r += 1) {
    for (let c = 0; c < BOARD_SIZE; c += 1) {
      if (board[r][c] === 0) empty.push([r, c])
    }
  }
  return empty
}

export function spawnRandomTile(board: number[][], random = Math.random): number[][] {
  const next = cloneBoard(board)
  const empty = getEmptyCells(next)
  if (empty.length === 0) return next
  const [row, col] = empty[Math.floor(random() * empty.length)]
  next[row][col] = random() < 0.9 ? 2 : 4
  return next
}

function slideAndMergeLine(line: number[]): { line: number[]; scoreGained: number; moved: boolean; won: boolean } {
  const compact = line.filter((value) => value !== 0)
  const merged: number[] = []
  let scoreGained = 0
  let won = false

  for (let i = 0; i < compact.length; i += 1) {
    const current = compact[i]
    const next = compact[i + 1]
    if (current !== undefined && current === next) {
      const value = current * 2
      merged.push(value)
      scoreGained += value
      if (value === 2048) won = true
      i += 1
    } else {
      merged.push(current)
    }
  }

  while (merged.length < BOARD_SIZE) merged.push(0)
  const moved = merged.some((value, index) => value !== line[index])
  return { line: merged, scoreGained, moved, won }
}

function getLine(board: number[][], index: number, direction: Direction): number[] {
  switch (direction) {
    case 'left':
      return [...board[index]]
    case 'right':
      return [...board[index]].reverse()
    case 'up':
      return board.map((row) => row[index])
    case 'down':
      return board.map((row) => row[index]).reverse()
  }
}

function setLine(board: number[][], index: number, direction: Direction, line: number[]): void {
  const output = direction === 'right' || direction === 'down' ? [...line].reverse() : line
  if (direction === 'left' || direction === 'right') {
    board[index] = output
    return
  }
  for (let r = 0; r < BOARD_SIZE; r += 1) {
    board[r][index] = output[r]
  }
}

export function applyMove(board: number[][], direction: Direction): MoveResult {
  const next = cloneBoard(board)
  let scoreGained = 0
  let moved = false
  let won = false

  for (let i = 0; i < BOARD_SIZE; i += 1) {
    const line = getLine(board, i, direction)
    const result = slideAndMergeLine(line)
    setLine(next, i, direction, result.line)
    scoreGained += result.scoreGained
    moved = moved || result.moved
    won = won || result.won
  }

  return { board: next, scoreGained, moved, won }
}

export function canMove(board: number[][]): boolean {
  if (getEmptyCells(board).length > 0) return true
  for (let r = 0; r < BOARD_SIZE; r += 1) {
    for (let c = 0; c < BOARD_SIZE; c += 1) {
      const value = board[r][c]
      if (board[r + 1]?.[c] === value || board[r]?.[c + 1] === value) return true
    }
  }
  return false
}

export function createInitialGame(random = Math.random): GameState {
  let board = createEmptyBoard()
  board = spawnRandomTile(board, random)
  board = spawnRandomTile(board, random)
  return { board, score: 0, status: 'playing' }
}

export function nextGameState(state: GameState, direction: Direction, random = Math.random): GameState {
  if (state.status === 'game-over') return state
  const result = applyMove(state.board, direction)
  if (!result.moved) return state
  const board = spawnRandomTile(result.board, random)
  const score = state.score + result.scoreGained
  const status: Status = result.won ? 'won' : canMove(board) ? 'playing' : 'game-over'
  return { board, score, status }
}
