import { useEffect, useMemo, useState } from 'react'
import { BOARD_SIZE, createInitialGame, nextGameState, type Direction, type GameState } from './game'

const keyToDirection: Record<string, Direction> = {
  ArrowUp: 'up',
  ArrowDown: 'down',
  ArrowLeft: 'left',
  ArrowRight: 'right',
  w: 'up',
  W: 'up',
  a: 'left',
  A: 'left',
  s: 'down',
  S: 'down',
  d: 'right',
  D: 'right',
}

function getStatusText(state: GameState): string {
  if (state.status === 'won') return 'You reached 2048! Keep going or restart.'
  if (state.status === 'game-over') return 'Game over! No more valid moves.'
  return 'Use arrow keys or WASD to combine tiles.'
}

function App() {
  const [game, setGame] = useState<GameState>(() => createInitialGame())

  useEffect(() => {
    const handleKeyDown = (event: KeyboardEvent) => {
      const direction = keyToDirection[event.key]
      if (!direction) return
      event.preventDefault()
      setGame((current) => nextGameState(current, direction))
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [])

  const cells = useMemo(() => game.board.flat(), [game.board])

  return (
    <main className="app-shell">
      <section className="game-panel">
        <div className="header-row">
          <div>
            <h1>2048</h1>
            <p className="subtitle">Slide matching numbers together and chase 2048.</p>
          </div>
          <div className="score-card" data-testid="score">
            <span>Score</span>
            <strong>{game.score}</strong>
          </div>
        </div>

        <div className="controls-row">
          <p data-testid="status" className="status-text">{getStatusText(game)}</p>
          <button data-testid="restart" onClick={() => setGame(createInitialGame())}>New Game</button>
        </div>

        <div
          className="board"
          data-testid="board"
          role="grid"
          aria-label="2048 board"
        >
          {cells.map((value, index) => (
            <div key={index} role="gridcell" className={`tile tile-${value || 'empty'}`}>
              {value === 0 ? '' : value}
            </div>
          ))}
        </div>

        <p className="footer-note">Controls: Arrow keys or WASD</p>
      </section>
    </main>
  )
}

export default App
